// Compute the [previous_friday, this_friday) window in ISO 8601.
// Used to bound the Gumroad and Plausible queries.
const now = new Date();
// 'this Friday' = today (since cron runs on Friday morning)
const thisFriday = new Date(now);
thisFriday.setUTCHours(0, 0, 0, 0);
const prevFriday = new Date(thisFriday);
prevFriday.setUTCDate(prevFriday.getUTCDate() - 7);
return [{
  json: {
    previous_friday: prevFriday.toISOString(),
    this_friday: thisFriday.toISOString(),
    week_ending: thisFriday.toISOString().slice(0, 10)
  }
}];

// Group sales by product, sum revenue, count refunds, compute net revenue
// (gross - refunds - 10% Gumroad fee). Output: per-product rollups + totals.
const sales = items[0].json.sales || [];
const byProduct = {};
let totalGross = 0;
let totalRefunds = 0;
let totalSales = 0;
for (const s of sales) {
  const slug = (s.product_permalink || s.permalink || 'unknown').split('/').pop();
  if (!byProduct[slug]) {
    byProduct[slug] = {
      slug,
      product_name: s.product_name,
      gross_cents: 0,
      refund_cents: 0,
      sales_count: 0,
      refund_count: 0
    };
  }
  const cents = parseInt(s.price, 10) || 0;
  byProduct[slug].gross_cents += cents;
  byProduct[slug].sales_count += 1;
  totalGross += cents;
  totalSales += 1;
  if (s.refunded === true || s.refunded === 'true') {
    byProduct[slug].refund_cents += cents;
    byProduct[slug].refund_count += 1;
    totalRefunds += cents;
  }
}
// Apply 10% Gumroad fee on net (gross - refunds).
for (const p of Object.values(byProduct)) {
  const netGross = p.gross_cents - p.refund_cents;
  p.net_revenue_cents = Math.round(netGross * 0.9);
  p.net_revenue_dollars = (p.net_revenue_cents / 100).toFixed(2);
  p.gross_dollars = (p.gross_cents / 100).toFixed(2);
}
const totalNet = Math.round((totalGross - totalRefunds) * 0.9);
return [{
  json: {
    by_product: byProduct,
    products: Object.values(byProduct),
    totals: {
      gross_cents: totalGross,
      refund_cents: totalRefunds,
      net_cents: totalNet,
      sales_count: totalSales,
      refund_count: Object.values(byProduct).reduce((a, p) => a + p.refund_count, 0),
      gross_dollars: (totalGross / 100).toFixed(2),
      net_dollars: (totalNet / 100).toFixed(2),
      refund_rate: totalSales ? ((totalRefunds / totalGross) * 100).toFixed(2) : '0.00'
    },
    week_ending: $node['Compute Date Window'].json.week_ending
  }
}];

// Compute conversion rate per product (sales / page views).
// Plausible aggregate only gives total pageviews; for per-product
// breakdown you'd query with filters. Here we approximate using the
// total and divide proportionally to product traffic if breakdown
// is unavailable.
const agg = $node['Aggregate by Product'].json;
const plausible = $node['Plausible — Page Views'].json;
const totalViews = plausible?.results?.pageviews?.value || 0;
const products = agg.products.map(p => ({
  ...p,
  // Naive even-split of pageviews; replace with per-page filtered
  // queries when you have multiple sales pages tracked separately.
  estimated_views: agg.products.length ? Math.round(totalViews / agg.products.length) : 0,
  conversion_rate: (agg.products.length && totalViews)
    ? ((p.sales_count / (totalViews / agg.products.length)) * 100).toFixed(2)
    : '0.00'
}));
return [{
  json: {
    ...agg,
    products,
    plausible_total_pageviews: totalViews,
    plausible_available: !!totalViews
  }
}];

// Append a new weekly row to revenue-tracker.md and conversion-tracker.md.
// Both files are expected to have a markdown table the bot extends.
const stats = $node['Compute Conversion Rates'].json;
const rev = $input.all()[0].json;       // GitHub — Read Revenue Tracker
const conv = $input.all()[1].json;      // GitHub — Read Conversion Tracker
const week = stats.week_ending;
const t = stats.totals;

// Revenue row: | week | total sales | gross | net | refund rate |
const revRow = `| ${week} | ${t.sales_count} | $${t.gross_dollars} | $${t.net_dollars} | ${t.refund_rate}% |`;
const revContent = Buffer.from(rev.content, 'base64').toString('utf-8') + '\n' + revRow;

// Conversion rows: one per product
const convRows = stats.products.map(p =>
  `| ${week} | ${p.slug} | ${p.sales_count} | ${p.estimated_views} | ${p.conversion_rate}% |`
).join('\n');
const convContent = Buffer.from(conv.content, 'base64').toString('utf-8') + '\n' + convRows;

return [{
  json: {
    revenue: {
      sha: rev.sha,
      content_b64: Buffer.from(revContent).toString('base64'),
      path: 'analytics/revenue-tracker.md'
    },
    conversion: {
      sha: conv.sha,
      content_b64: Buffer.from(convContent).toString('base64'),
      path: 'analytics/conversion-tracker.md'
    },
    week_ending: week,
    totals: t,
    products: stats.products
  }
}];

