// Build the weekly Slack/email summary.
const data = $node['Build Updated Trackers'].json;
const t = data.totals;
const products = data.products.slice().sort((a, b) => b.sales_count - a.sales_count);
const top = products[0] || { product_name: '(none)', sales_count: 0 };
const summary = `Week ending ${data.week_ending}:\n` +
  `- Total revenue (net): $${t.net_dollars} (gross $${t.gross_dollars})\n` +
  `- Total sales: ${t.sales_count}\n` +
  `- Top product: ${top.product_name} (${top.sales_count} sales)\n` +
  `- Refunds: ${t.refund_count} (rate: ${t.refund_rate}%)`;
return [{ json: { summary, week_ending: data.week_ending } }];
